import{_ as e,o as r,c as a,a2 as n}from"./chunks/framework.BWuWLRhz.js";const p="/images/its-2020-and-youre-in-the-future/1-1.png",i="/images/its-2020-and-youre-in-the-future/7.png",o="/images/its-2020-and-youre-in-the-future/3-1.png",s="/images/its-2020-and-youre-in-the-future/2.png",u="/images/its-2020-and-youre-in-the-future/6-1.png",h="/images/its-2020-and-youre-in-the-future/8.png",l="/images/its-2020-and-youre-in-the-future/9-1.png",c="/images/its-2020-and-youre-in-the-future/10-2.png",m="/images/its-2020-and-youre-in-the-future/4-1.png",f="/images/its-2020-and-youre-in-the-future/5-1.png",g="/images/its-2020-and-youre-in-the-future/pinit_fg_en_rect_gray_20.png",q=JSON.parse(`{"title":"It's 2020 and you're in the future","description":"","frontmatter":{"title":"It's 2020 and you're in the future","titleZh":"已是2020年 你已身处未来","date":"2020-01-02T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2020/01/its-2020-and-youre-in-the-future.html","slug":"its-2020-and-youre-in-the-future"},"headers":[],"relativePath":"posts/its-2020-and-youre-in-the-future.md","filePath":"posts/its-2020-and-youre-in-the-future.md","lastUpdated":1782886257000}`),_={name:"posts/its-2020-and-youre-in-the-future.md"};function d(w,t,y,b,k,T){return r(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="已是2020年-你已身处未来-·-it-s-2020-and-you-re-in-the-future" tabindex="-1">已是2020年 你已身处未来 · It&#39;s 2020 and you&#39;re in the future <a class="header-anchor" href="#已是2020年-你已身处未来-·-it-s-2020-and-you-re-in-the-future" aria-label="Permalink to &quot;已是2020年 你已身处未来 · It&#39;s 2020 and you&#39;re in the future&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2020/01/its-2020-and-youre-in-the-future.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2020/01/its-2020-and-youre-in-the-future.html</a> · 2020-01-02</p></blockquote><p>终于进入 2020 年代了。过去 20 年我们一直没法给自己所在的这个十年起个顺口的名字,现在总算解脱了——接下来 80 年一直到 2100 年之前都不用愁了,到那时我猜 <a href="https://waitbutwhy.com/2015/01/artificial-intelligence-revolution-1.html" target="_blank" rel="noreferrer">AGI</a> 应该已经想好该怎么称呼 2100 到 2120 之间那两个十年了。</p><p>我们现在活在 20 年代!好激动。「the twenties」听起来超级正统,而且特别有年代感。40 年代显得老,30 年代更老。但没什么比咆哮的 20 年代 (Roaring 20s) 更有老派味儿了。</p><p>现在轮到我们负责把这个十年搞得酷一点了,这样 100 年后的人回头看 2020 年代觉得「天啊真是复古」的时候,那种复古是酷酷的迷人的复古,而不是无聊烂糟糟的那种。</p><p>还有一件怪事是,对我们来说,2020 年代听起来像个超炫的未来十年——而 100 年前的今天,人们对 1920 年代也是同样的感觉。他们都习惯了 19 十几年那种叫法,突然一下就变成:「哇塞我们进入<em>二十年代</em>了!」然后他们又开始郁闷,想着自己 1910 年时以为到 1920 年自己人生该有多大成就,结果差得远呢。</p><p>不管怎么说,这是发一篇「妈的我们老了」帖子的完美时机。</p><p>以下是一些 2020 新年的时间冷知识:</p><p>二战爆发的时候,美国人感觉南北战争距离他们就跟我们现在感觉二战一样远。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2020/01/1-1.png" target="_blank" rel="noreferrer"><img src="'+p+'" alt=""></a></p><p>说到二战,两次世界大战其实靠得挺近的。如果二战是今天爆发,那一战对我们来说就跟 9/11 差不多那么久远。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2020/01/7.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt=""></a></p><p>苏联解体现在对我们的记忆遥远程度,就跟苏联解体那会儿肯尼迪 (JFK) 遇刺对当时的人一样遥远。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2020/01/3-1.png" target="_blank" rel="noreferrer"><img src="'+o+'" alt=""></a></p><p>来点无聊话题:自从 1993 年牛仔队对比尔队那场超级碗以来打过的超级碗,已经比那之前打过的所有超级碗加起来还多了。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2020/01/2.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt=""></a></p><p>还有,西德 1974 年赢的那届世界杯,离 1930 年首届世界杯比离今天还近。</p><p>《纯真年代 (The Wonder Years)》这部剧 1988 到 1993 年播出,讲的是 1968 到 1973 年间的故事。我当时看的时候,感觉那是很久很久以前的事情了。如果今天有一部新版《纯真年代》首播,它讲的会是 2000 到 2005 年之间的故事。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2020/01/6-1.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt=""></a></p><p>还有,还记得《侏罗纪公园》《狮子王》《阿甘正传》在电影院上映的时候吗?那时候距离阿波罗登月比距离今天还近。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2020/01/8.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt=""></a></p><p>千年虫 (Y2K) 呢?离 70 年代比离今天还近。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2020/01/9-1.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt=""></a></p><p>与此同时,辛普森 (O.J. Simpson) 案审判现在正好处于 1960 年代和今天的中点。而且离查尔斯·曼森 (Charles Manson) 案审判更近。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2020/01/10-2.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt=""></a></p><p>至于你嘛,如果你 60 岁或以上,那你的出生日期离 1800 年代比离今天还要近。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2020/01/4-1.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt=""></a></p><p>今天 35 岁的人,出生日期离 1940 年代比离今天更近。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2020/01/5-1.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt=""></a></p><p>这类计算还有很多可玩的花样,但这两个在我看来最让人抑郁。值得一提的是,我 94 岁的奶奶,出生日期离安德鲁·杰克逊 (Andrew Jackson) 政府时期比离今天还要近。</p><p>如果你像我一样出生在 1980 年代,那么今天一个和你在 1990 年时同龄的小孩,整整比你小了一代人——30 年。他们记住奥巴马任期的方式,就像你记住里根任期一样。9/11 对他们来说,就是登月对你来说的那种存在。1990 年代对他们来说的古老感,就跟 1960 年代对你来说的古老感差不多。对你而言,1970 年代不过是你出生前不久的事——他们对 2000 年代就是这么想的。他们看 1970 年代,就像你看 1940 年代。而嬉皮士的 1960 年代对他们的年代感,就相当于大萧条对你的年代感。</p><p>但今天的这些小孩最诡异的一点是:他们中的大多数,会活着见到 2100 年代。</p><h2 id="抱歉-如果这让你有点焦虑。新年快乐" tabindex="-1">抱歉,如果这让你有点焦虑。新年快乐! <a class="header-anchor" href="#抱歉-如果这让你有点焦虑。新年快乐" aria-label="Permalink to &quot;抱歉,如果这让你有点焦虑。新年快乐!&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请订阅我们的<a href="https://mailchi.mp/waitbutwhy/email-signup" target="_blank" rel="noreferrer">邮件列表</a>,新文章一发布我们就发给你。绝不烦人。</p><p>如果你喜欢时间轴,那你接下来<a href="https://waitbutwhy.com/2013/08/putting-time-in-perspective.html" target="_blank" rel="noreferrer">大概该去这儿</a>。</p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2020/01/its-2020-and-youre-in-the-future.html&amp;description=It%E2%80%99s%202020%20and%20you%E2%80%99re%20in%20the%20future" target="_blank" rel="noreferrer"><img src="'+g+'" alt=""></a></p>',37)])])}const A=e(_,[["render",d]]);export{q as __pageData,A as default};
